import bcrypt from 'bcryptjs';
import { SignJWT, jwtVerify } from 'jose';
import { cookies } from 'next/headers';
import { env } from './env';
import { db } from './db';

const JWT_SECRET = new TextEncoder().encode(
  env.JWT_SECRET || 'fallback-secret-min-32-characters-long'
);

const SESSION_DURATION = 60 * 60 * 24 * 7; // 7 days

export interface Session {
  id: string;
  userId: string;
  email: string;
  name: string;
  role: 'admin' | 'editor';
  expiresAt: Date;
}

// Hash password with bcrypt
export async function hashPassword(password: string): Promise<string> {
  return bcrypt.hash(password, 12);
}

// Verify password
export async function verifyPassword(password: string, hashedPassword: string): Promise<boolean> {
  return bcrypt.compare(password, hashedPassword);
}

// Create JWT token
export async function createToken(payload: object): Promise<string> {
  return new SignJWT({ ...payload })
    .setProtectedHeader({ alg: 'HS256' })
    .setIssuedAt()
    .setExpirationTime('7d')
    .sign(JWT_SECRET);
}

// Verify JWT token
export async function verifyToken(token: string): Promise<Session | null> {
  try {
    const { payload } = await jwtVerify(token, JWT_SECRET);
    return payload as Session;
  } catch {
    return null;
  }
}

// Create session
export async function createSession(userId: string, email: string, name: string): Promise<string> {
  const token = await createToken({
    userId,
    email,
    name,
    role: 'admin',
    expiresAt: new Date(Date.now() + SESSION_DURATION * 1000),
  });

  // Store in database
  await db.session.create({
    data: {
      token,
      userId,
      expiresAt: new Date(Date.now() + SESSION_DURATION * 1000),
    },
  });

  return token;
}

// Get current session from cookies
export async function getSession(): Promise<Session | null> {
  const cookieStore = await cookies();
  const token = cookieStore.get('admin-session')?.value;

  if (!token) return null;

  const session = await verifyToken(token);
  if (!session) return null;

  // Check if session is expired
  if (new Date() > new Date(session.expiresAt)) {
    await deleteSession(token);
    return null;
  }

  return session;
}

// Delete session
export async function deleteSession(token: string): Promise<void> {
  const cookieStore = await cookies();
  cookieStore.delete('admin-session');

  try {
    await db.session.delete({
      where: { token },
    });
  } catch {
    // Session might not exist in DB
  }
}

// Set session cookie
export async function setSessionCookie(token: string): Promise<void> {
  const cookieStore = await cookies();
  cookieStore.set('admin-session', token, {
    httpOnly: true,
    secure: env.NODE_ENV === 'production',
    sameSite: 'strict',
    maxAge: SESSION_DURATION,
    path: '/',
  });
}

// Rate limiting for login attempts
const loginAttempts = new Map<string, { count: number; resetAt: number }>();

export function checkRateLimit(identifier: string): boolean {
  const now = Date.now();
  const attempt = loginAttempts.get(identifier);

  if (!attempt || now > attempt.resetAt) {
    loginAttempts.set(identifier, {
      count: 1,
      resetAt: now + 15 * 60 * 1000, // 15 minutes
    });
    return true;
  }

  if (attempt.count >= 5) {
    return false;
  }

  attempt.count++;
  return true;
}

// Clear rate limit
export function clearRateLimit(identifier: string): void {
  loginAttempts.delete(identifier);
}

// Generate secure random token
export function generateSecureToken(length: number = 32): string {
  const chars = 'REDACTED';
  let token = '';
  for (let i = 0; i < length; i++) {
    token += chars.charAt(Math.floor(Math.random() * chars.length));
  }
  return token;
}

import { z } from 'zod';

const envSchema = z.object({
  // Database
  DATABASE_URL: z.string().default('file:./dev.db'),

  // Auth
  ADMIN_PASSWORD: z.string().min(8).optional(),
  JWT_SECRET: z.string().min(32).optional(),

  // Passkeys (WebAuthn)
  PASSKEY_RP_ID: z.string().optional(),
  PASSKEY_RP_NAME: z.string().default('Douglas Mitchell Portfolio'),
  PASSKEY_EXPECTED_ORIGINS: z.string().optional(),

  // Redis/Cache
  UPSTASH_REDIS_URL: z.string().optional(),
  UPSTASH_REDIS_TOKEN: z.string().optional(),

  // Storage
  STORAGE_PROVIDER: z.enum(['local', 's3', 'r2']).default('local'),
  S3_BUCKET: z.string().optional(),
  S3_REGION: z.string().default('us-east-1'),
  S3_ACCESS_KEY: z.string().optional(),
  S3_SECRET_KEY: z.string().optional(),

  // Upload limits
  MAX_FILE_SIZE: z.string().default('50'), // MB
  UPLOAD_DIR: z.string().default('./public/uploads'),

  // App config
  NODE_ENV: z.enum(['development', 'production', 'test']).default('development'),
  NEXT_PUBLIC_SITE_URL: z.string().url().default('https://douglasmitchell.info'),

  // Features
  ENABLE_PASSKEYS: z.string().default('true'),
  ENABLE_ANALYTICS: z.string().default('false'),

  // Email
  SMTP_HOST: z.string().optional(),
  SMTP_PORT: z.string().default('587'),
  SMTP_USER: z.string().optional(),
  SMTP_PASS: z.string().optional(),
  FROM_EMAIL: z.string().email().optional(),
});

let validatedEnv: z.infer<typeof envSchema> | null = null;

export function getEnv() {
  if (validatedEnv) return validatedEnv;

  try {
    validatedEnv = envSchema.parse(process.env);
    return validatedEnv;
  } catch (error) {
    if (error instanceof z.ZodError) {
      console.error('Environment validation failed:');
      error.errors.forEach((err) => {
        console.error(`  - ${err.path.join('.')}: ${err.message}`);
      });
    }
    throw new Error('Invalid environment variables');
  }
}

// Type-safe env export
export const env = getEnv();

// Feature flags
export const features = {
  passkeys: env.ENABLE_PASSKEYS === 'true' && env.ADMIN_PASSWORD,
  analytics: env.ENABLE_ANALYTICS === 'true',
  email: env.SMTP_HOST && env.SMTP_USER && env.SMTP_PASS,
  s3: env.STORAGE_PROVIDER === 's3' && env.S3_BUCKET && env.S3_ACCESS_KEY,
  redis: env.UPSTASH_REDIS_URL && env.UPSTASH_REDIS_TOKEN,
} as const;

import { mkdir, writeFile } from 'fs/promises';
import { existsSync } from 'fs';
import { join, extname, basename } from 'path';
import sharp from 'sharp';
import { v4 as uuidv4 } from 'uuid';

// File type configurations
export const ALLOWED_MIME_TYPES = {
  image: ['image/jpeg', 'image/png', 'image/gif', 'image/webp', 'image/avif', 'image/svg+xml'],
  video: ['video/mp4', 'video/webm', 'video/ogg'],
  audio: ['audio/mpeg', 'audio/wav', 'audio/ogg', 'audio/webm'],
  document: [
    'application/pdf',
    'application/msword',
    'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
    'application/vnd.ms-excel',
    'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
    'text/plain',
    'text/markdown',
  ],
};

const MAX_FILE_SIZE = 50 * 1024 * 1024; // 50MB
const UPLOAD_DIR = process.env.UPLOAD_DIR || './public/uploads';

export interface FileValidationResult {
  valid: boolean;
  error?: string;
}

export interface UploadResult {
  success: boolean;
  id?: string;
  filename?: string;
  originalName: string;
  mimeType: string;
  size: number;
  width?: number;
  height?: number;
  duration?: number;
  url?: string;
  thumbnailUrl?: string;
  error?: string;
}

// Validate file type
export function validateFileType(mimeType: string): FileValidationResult {
  const allAllowed = Object.values(ALLOWED_MIME_TYPES).flat();

  if (allAllowed.includes(mimeType)) {
    return { valid: true };
  }

  return {
    valid: false,
    error: `File type ${mimeType} is not allowed. Allowed types: images, videos, audio, documents`,
  };
}

// Validate file size
export function validateFileSize(size: number): FileValidationResult {
  if (size <= MAX_FILE_SIZE) {
    return { valid: true };
  }

  return {
    valid: false,
    error: `File size ${formatFileSize(size)} exceeds maximum of ${formatFileSize(MAX_FILE_SIZE)}`,
  };
}

// Format file size for display
export function formatFileSize(bytes: number): string {
  if (bytes === 0) return '0 Bytes';
  const k = 1024;
  const sizes = ['Bytes', 'KB', 'MB', 'GB'];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
}

// Get file category
export function getFileCategory(mimeType: string): 'image' | 'video' | 'audio' | 'document' | 'unknown' {
  if (ALLOWED_MIME_TYPES.image.includes(mimeType)) return 'image';
  if (ALLOWED_MIME_TYPES.video.includes(mimeType)) return 'video';
  if (ALLOWED_MIME_TYPES.audio.includes(mimeType)) return 'audio';
  if (ALLOWED_MIME_TYPES.document.includes(mimeType)) return 'document';
  return 'unknown';
}

// Generate unique filename
export function generateUniqueFilename(originalName: string): string {
  const ext = extname(originalName);
  const uniqueId = uuidv4();
  return `${uniqueId}${ext}`;
}

// Get image dimensions
export async function getImageDimensions(buffer: Buffer): Promise<{ width: number; height: number } | null> {
  try {
    const metadata = await sharp(buffer).metadata();
    if (metadata.width && metadata.height) {
      return { width: metadata.width, height: metadata.height };
    }
    return null;
  } catch {
    return null;
  }
}

// Create thumbnail for images
export async function createThumbnail(
  buffer: Buffer,
  filename: string,
  width: number = 300
): Promise<string | null> {
  try {
    const thumbnailDir = join(UPLOAD_DIR, 'thumbnails');
    if (!existsSync(thumbnailDir)) {
      await mkdir(thumbnailDir, { recursive: true });
    }

    const thumbnailFilename = `thumb-${width}-${filename}`;
    const thumbnailPath = join(thumbnailDir, thumbnailFilename);

    await sharp(buffer)
      .resize(width, null, { withoutEnlargement: true })
      .jpeg({ quality: 80 })
      .toFile(thumbnailPath);

    return `/uploads/thumbnails/${thumbnailFilename}`;
  } catch (error) {
    console.error('Thumbnail creation failed:', error);
    return null;
  }
}

// Optimize image
export async function optimizeImage(buffer: Buffer, mimeType: string): Promise<Buffer> {
  try {
    if (mimeType === 'image/svg+xml') {
      return buffer; // Don't optimize SVGs
    }

    const sharpInstance = sharp(buffer);

    // Resize if too large
    const metadata = await sharpInstance.metadata();
    if (metadata.width && metadata.width > 2048) {
      sharpInstance.resize(2048, null, { withoutEnlargement: true });
    }

    // Convert to WebP for better compression
    if (mimeType !== 'image/webp' && mimeType !== 'image/avif') {
      return await sharpInstance.webp({ quality: 85 }).toBuffer();
    }

    return await sharpInstance.toBuffer();
  } catch {
    return buffer; // Return original if optimization fails
  }
}

// Save file to disk
export async function saveFile(
  buffer: Buffer,
  filename: string,
  category: string
): Promise<string> {
  const categoryDir = join(UPLOAD_DIR, category);

  if (!existsSync(categoryDir)) {
    await mkdir(categoryDir, { recursive: true });
  }

  const filePath = join(categoryDir, filename);
  await writeFile(filePath, buffer);

  return `/uploads/${category}/${filename}`;
}

// Process file upload
export async function processFileUpload(
  file: File,
  options: {
    createThumbnail?: boolean;
    optimizeImages?: boolean;
  } = {}
): Promise<UploadResult> {
  const { createThumbnail: shouldCreateThumbnail = true, optimizeImages = true } = options;

  try {
    // Validate
    const typeValidation = validateFileType(file.type);
    if (!typeValidation.valid) {
      return { success: false, error: typeValidation.error, originalName: file.name, mimeType: file.type, size: file.size };
    }

    const sizeValidation = validateFileSize(file.size);
    if (!sizeValidation.valid) {
      return { success: false, error: sizeValidation.error, originalName: file.name, mimeType: file.type, size: file.size };
    }

    const category = getFileCategory(file.type);
    const uniqueFilename = generateUniqueFilename(file.name);

    // Convert File to Buffer
    const bytes = await file.arrayBuffer();
    let buffer = Buffer.from(bytes);

    let width: number | undefined;
    let height: number | undefined;
    let duration: number | undefined;
    let thumbnailUrl: string | undefined;

    // Process based on file type
    if (category === 'image') {
      // Get dimensions
      const dimensions = await getImageDimensions(buffer);
      if (dimensions) {
        width = dimensions.width;
        height = dimensions.height;
      }

      // Optimize
      if (optimizeImages) {
        buffer = await optimizeImage(buffer, file.type);
      }

      // Create thumbnail
      if (shouldCreateThumbnail && dimensions) {
        thumbnailUrl = await createThumbnail(buffer, uniqueFilename);
      }
    }

    // Save file
    const url = await saveFile(buffer, uniqueFilename, category);

    return {
      success: true,
      id: uuidv4(),
      filename: uniqueFilename,
      originalName: file.name,
      mimeType: file.type,
      size: file.size,
      width,
      height,
      duration,
      url,
      thumbnailUrl,
    };
  } catch (error) {
    console.error('File upload error:', error);
    return {
      success: false,
      error: 'Failed to process file upload',
      originalName: file.name,
      mimeType: file.type,
      size: file.size,
    };
  }
}

// Get file icon based on type
export function getFileIcon(mimeType: string): string {
  const category = getFileCategory(mimeType);

  const icons = {
    image: '🖼️',
    video: '🎬',
    audio: '🎵',
    document: '📄',
    unknown: '📎',
  };

  return icons[category];
}

// Check if file is previewable
export function isPreviewable(mimeType: string): boolean {
  return getFileCategory(mimeType) !== 'unknown';
}

import { NextRequest, NextResponse } from 'next/server';
import { db } from '@/lib/db';
import { hashPassword, verifyPassword, createSession, setSessionCookie, checkRateLimit } from '@/lib/auth';
import { env } from '@/lib/env';

// GET /api/admin/auth - Check current session
export async function GET() {
  try {
    // Get session from cookie
    const cookieStore = await import('next/headers').then(m => m.cookies());
    const token = cookieStore.get('admin-session')?.value;

    if (!token) {
      return NextResponse.json({ authenticated: false }, { status: 401 });
    }

    // Verify token
    const { jwtVerify } = await import('jose');
    const secret = new TextEncoder().encode(env.JWT_SECRET || 'fallback-secret');

    try {
      const { payload } = await jwtVerify(token, secret);
      return NextResponse.json({ 
        authenticated: true, 
        user: {
          userId: payload.userId,
          email: payload.email,
          name: payload.name,
          role: payload.role,
        }
      });
    } catch {
      return NextResponse.json({ authenticated: false }, { status: 401 });
    }
  } catch (error) {
    console.error('Auth check error:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

// POST /api/admin/auth - Login
export async function POST(request: NextRequest) {
  try {
    const body = await request.json();
    const { email, password } = body;

    // Validation
    if (!email || !password) {
      return NextResponse.json(
        { error: 'Email and password are required' },
        { status: 400 }
      );
    }

    // Rate limiting
    const clientIp = request.headers.get('x-forwarded-for') || 'unknown';
    if (!checkRateLimit(clientIp)) {
      return NextResponse.json(
        { error: 'Too many login attempts. Please try again later.' },
        { status: 429 }
      );
    }

    // Find user
    const user = await db.adminUser.findUnique({
      where: { email },
    });

    if (!user) {
      return NextResponse.json(
        { error: 'Invalid credentials' },
        { status: 401 }
      );
    }

    // Verify password
    const isValid = await verifyPassword(password, user.passwordHash);

    if (!isValid) {
      return NextResponse.json(
        { error: 'Invalid credentials' },
        { status: 401 }
      );
    }

    // Update last login
    await db.adminUser.update({
      where: { id: user.id },
      data: { lastLoginAt: new Date() },
    });

    // Create session
    const token = await createSession(user.id, user.email, user.name || 'Admin');
    await setSessionCookie(token);

    return NextResponse.json({
      success: true,
      user: {
        id: user.id,
        email: user.email,
        name: user.name,
        role: user.role,
      },
    });
  } catch (error) {
    console.error('Login error:', error);
    return NextResponse.json(
      { error: 'Internal server error' },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { db } from '@/lib/db';

export async function POST(request: NextRequest) {
  try {
    const body = await request.json();
    const { name, email, message, source } = body;

    // Validate required fields
    if (!name || !email || !message) {
      return NextResponse.json(
        { error: 'Missing required fields' },
        { status: 400 }
      );
    }

    // Validate email format
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(email)) {
      return NextResponse.json(
        { error: 'Invalid email format' },
        { status: 400 }
      );
    }

    // Store in database (when database is available)
    try {
      await db.contactSubmission.create({
        data: {
          name,
          email,
          message,
          source: source || 'website',
          status: 'new',
        },
      });
    } catch {
      // If database fails, still return success but log
      console.log('Contact submission:', { name, email, message });
    }

    return NextResponse.json({
      success: true,
      message: 'Contact submission received',
    });
  } catch (error) {
    console.error('Contact submission error:', error);
    return NextResponse.json(
      { error: 'Internal server error' },
      { status: 500 }
    );
  }
}

